// 三载体一致:纯 JS 力求解器,无 DOM;每 tick 读 node.x/node.y 自绘;命名导出
import { forceSimulation, forceManyBody, forceLink, forceCenter } from 'https://cdn.jsdelivr.net/npm/d3-force@3.0.0/+esm';
const sim = forceSimulation(data.nodes)
  .force('charge', forceManyBody().strength(-30))
  .force('link', forceLink(data.links).id(d => d.id).distance(30))
  .force('center', forceCenter(width / 2, height / 2))
  .on('tick', () => { /* 读 node.x, node.y → 重绘 canvas/SVG */ });
